var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_QM","text":{"KOREA":"흠흠, 좋아. 부엌에서 풍기던 향기 그대로야.","JPN":"ふんふん、よし。キッチンで漂ってた匂いとそっくり。","ENG":"Ahem. Good. The kitchen smells how it always has.","TWN":"嗯嗯，好了。跟廚房裡的香味一模一樣。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_QM","text":{"KOREA":"배는 안 고프시려나? 치킨 수프도 있으면 좋았을 텐데…….","JPN":"お腹は空いていらっしゃらないかな？　チキンスープもあればよかったんだけど……","ENG":"I wonder if she's hungry. It would've been better if we had some chicken soup too...","TWN":"你不餓嗎？要是有雞湯就好了……"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"으음, 음…….","JPN":"うーん、うん……","ENG":"Mm... Ngh...","TWN":"呃嗯，嗯……"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이 목소리는……. 분명…….","JPN":"この声は……確か……","ENG":"That voice... It has to be–","TWN":"這聲音……分明是……"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"콜록!! 콜록!! 하아……! 하……!","JPN":"ゴホッ！！　ゴホッ！！　はあ……！　は……！","ENG":"*Cough!!* *Cough!!* *Huff...* *Huff...!*","TWN":"咳咳！！咳咳！！哈啊……！哈……！"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_QM","text":{"KOREA":"앗! 안 돼요, 부학회장님! 지금 일어나려고 하시면……!","JPN":"あっ！　だめですよ、副学会長様！　今起き上がろうとされては……！","ENG":"Huh?! No, Vice President! Don't try to get up...!","TWN":"啊！不可以，副學會長！你現在起來的話……！"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_QM","text":{"KOREA":"부학회장님, 괜찮으세요?","JPN":"副学会長様、大丈夫ですか？","ENG":"Are you okay?","TWN":"副學會長，你沒事吧？"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_QM","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"콜록, 어떻게…… 어떻게 된 거예요? 제가 왜…….","JPN":"ゲホッ……どうして……どうなっているのですか？　私はなぜ……","ENG":"*Cough* What... What happened? Why am I...?","TWN":"咳咳，怎麼……怎麼回事？我為什麼……"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_QM","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_QM","text":{"KOREA":"몸을 뒤척이시다 침대에서 굴러 떨어지셨어요.","JPN":"寝返りをうたれた際にベッドから転げ落ちられたのです。","ENG":"You fell off your bed while you were sleeping.","TWN":"你翻身的時候從床上滾下來了。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_QM","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_QM","text":{"KOREA":"그래도 정신이 드셔서 다행이에요. 한동안 죽은 듯이 주무시기만 해서 걱정했어요.","JPN":"ですが、お目覚めになられて安心しました。しばらく死んだように眠っていらしたので心配していたんです。","ENG":"But I'm glad you finally woke up. You've been sleeping for so long that I was getting worried.","TWN":"不過幸好你清醒過來了。你像死掉一樣睡了好久，我很擔心你。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_QM","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"제가 왜 이런 데 있죠? 분명 서재에서 잠시 눈을 붙였는데….","JPN":"私はなぜこんなところにいるのでしょうか？　書斎で仮眠をとっていたはずですのに……","ENG":"Why am I here? I am certain I fell asleep in my office...","TWN":"我為什麼會在這裡？我明明就是在書房裡打瞌睡……"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_QM","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"머리가 무거워…. 몸은 또 왜 이렇게 욱신거리는 거죠…?","JPN":"頭が重い……体もひどく痛むようですし……","ENG":"My head is throbbing... And why does my body feel so heavy...?","TWN":"頭好重……身體又為什麼這麼酸痛……？"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_QM","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_QM","text":{"KOREA":"편찮으셔서 그래요. 요양을 하러 오셨다고 전해 들었거든요.","JPN":"お体の具合が良くないからだと思います。療養に来られたと聞きました。","ENG":"You're ill. I was told you came here to recuperate.","TWN":"因為你生病了，我聽說你是來休養的。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_QM","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_QM","text":{"KOREA":"여기 있는 뱅쇼 좀 드셔 보세요. 기운이 좀 나실 거예요.","JPN":"ホットワインはいかがですか？　元気がでますよ。","ENG":"Here, have some vin chaud. It'll make you feel better.","TWN":"請你嘗嘗這裡的熱紅酒。喝了之後就會有精神了。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_QM","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"후우…. 고마워요. 이제 좀 살겠어요.","JPN":"ふう……ありがとう。生き返った気がしますわ。","ENG":"Huu... Thank you. I do feel a lot better now.","TWN":"呼……謝謝你，我感覺好多了。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_QM","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_QM","text":{"KOREA":"역시 잘 들을 줄 알았어요. 감기에 걸렸을 때는 뱅쇼가 즉효약이거든요.","JPN":"思っていたとおり効き目がありましたね。風邪にはホットワインがよく効くんです。","ENG":"I knew it would do wonders. Vin chaud always does the trick for my colds.","TWN":"我就知道會有效。感冒的時候，熱紅酒就是特效藥。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_QM","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"감기 말인가요?","JPN":"風邪ですか？","ENG":"Colds?","TWN":"感冒嗎？"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_QM","face":"UNIT_IDLE"}}}}]`);export{e as default};